import React, { useState, useEffect } from 'react';
import axios from 'axios';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
  ArcElement,
  PointElement,
  LineElement,
} from 'chart.js';
import { Bar, Pie, Line, Doughnut } from 'react-chartjs-2';

// Register ChartJS components
ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
  ArcElement,
  PointElement,
  LineElement
);

/**
 * Reports page component with analytics and charts
 */
const Reports = () => {
  const [loading, setLoading] = useState(true);
  const [taskStats, setTaskStats] = useState({
    total: 0,
    completed: 0,
    pending: 0,
    inProgress: 0
  });
  const [employeeStats, setEmployeeStats] = useState({
    total: 0,
    active: 0,
    inactive: 0,
    onLeave: 0,
    departments: []
  });
  const [tasks, setTasks] = useState([]);

  // Fetch data on mount
  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const [tasksRes, employeesRes, dashboardRes] = await Promise.all([
        axios.get('http://localhost:5000/api/tasks'),
        axios.get('http://localhost:5000/api/employees'),
        axios.get('http://localhost:5000/api/dashboard/stats')
      ]);

      const allTasks = tasksRes.data;
      const allEmployees = employeesRes.data;
      const stats = dashboardRes.data;

      // Calculate task statistics
      setTaskStats({
        total: allTasks.length,
        completed: allTasks.filter(t => t.status === 'completed').length,
        pending: allTasks.filter(t => t.status === 'pending').length,
        inProgress: allTasks.filter(t => t.status === 'in-progress').length
      });

      // Calculate employee statistics
      const departments = {};
      allEmployees.forEach(emp => {
        departments[emp.department] = (departments[emp.department] || 0) + 1;
      });

      setEmployeeStats({
        total: allEmployees.length,
        active: allEmployees.filter(e => e.status === 'active').length,
        inactive: allEmployees.filter(e => e.status === 'inactive').length,
        onLeave: allEmployees.filter(e => e.status === 'on-leave').length,
        departments: Object.entries(departments).map(([name, value]) => ({ name, value }))
      });

      setTasks(allTasks);
    } catch (error) {
      console.error('Error fetching data:', error);
    } finally {
      setLoading(false);
    }
  };

  // Chart configurations
  const barChartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'top',
        labels: { color: '#9ca3af' }
      }
    },
    scales: {
      x: {
        ticks: { color: '#9ca3af' },
        grid: { color: '#374151' }
      },
      y: {
        ticks: { color: '#9ca3af' },
        grid: { color: '#374151' }
      }
    }
  };

  // Task status bar chart data
  const taskStatusData = {
    labels: ['Pending', 'In Progress', 'Completed'],
    datasets: [
      {
        label: 'Tasks by Status',
        data: [taskStats.pending, taskStats.inProgress, taskStats.completed],
        backgroundColor: ['rgba(251, 191, 36, 0.8)', 'rgba(59, 130, 246, 0.8)', 'rgba(34, 197, 94, 0.8)'],
        borderColor: ['rgb(251, 191, 36)', 'rgb(59, 130, 246)', 'rgb(34, 197, 94)'],
        borderWidth: 1,
        borderRadius: 8
      }
    ]
  };

  // Employee status pie chart data
  const employeeStatusData = {
    labels: ['Active', 'On Leave', 'Inactive'],
    datasets: [
      {
        data: [employeeStats.active, employeeStats.onLeave, employeeStats.inactive],
        backgroundColor: [
          'rgba(34, 197, 94, 0.8)',
          'rgba(251, 191, 36, 0.8)',
          'rgba(107, 114, 128, 0.8)'
        ],
        borderColor: [
          'rgb(34, 197, 94)',
          'rgb(251, 191, 36)',
          'rgb(107, 114, 128)'
        ],
        borderWidth: 2
      }
    ]
  };

  // Department distribution doughnut chart
  const departmentData = {
    labels: employeeStats.departments.map(d => d.name),
    datasets: [
      {
        data: employeeStats.departments.map(d => d.value),
        backgroundColor: [
          'rgba(59, 130, 246, 0.8)',
          'rgba(168, 85, 247, 0.8)',
          'rgba(236, 72, 153, 0.8)',
          'rgba(34, 197, 94, 0.8)',
          'rgba(251, 191, 36, 0.8)',
          'rgba(249, 115, 22, 0.8)',
          'rgba(139, 92, 246, 0.8)'
        ],
        borderWidth: 0
      }
    ]
  };

  // Task completion trend (mock data for demo)
  const trendData = {
    labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'],
    datasets: [
      {
        label: 'Completed Tasks',
        data: [12, 19, 25, 32, 45, 60],
        borderColor: 'rgb(34, 197, 94)',
        backgroundColor: 'rgba(34, 197, 94, 0.1)',
        tension: 0.4,
        fill: true
      },
      {
        label: 'New Tasks',
        data: [15, 22, 18, 35, 40, 55],
        borderColor: 'rgb(59, 130, 246)',
        backgroundColor: 'rgba(59, 130, 246, 0.1)',
        tension: 0.4,
        fill: true
      }
    ]
  };

  // Priority distribution
  const priorityData = {
    labels: ['Low', 'Medium', 'High'],
    datasets: [
      {
        data: [
          tasks.filter(t => t.priority === 'low').length,
          tasks.filter(t => t.priority === 'medium').length,
          tasks.filter(t => t.priority === 'high').length
        ],
        backgroundColor: [
          'rgba(34, 197, 94, 0.8)',
          'rgba(251, 191, 36, 0.8)',
          'rgba(239, 68, 68, 0.8)'
        ],
        borderWidth: 0
      }
    ]
  };

  if (loading) {
    return <div className="p-6 flex items-center justify-center h-screen">Loading reports...</div>;
  }

  return (
    <div className="p-6">
      {/* Header */}
      <div className="mb-8">
        <h2 className="text-3xl font-bold bg-gradient-to-r from-green-400 to-blue-500 bg-clip-text text-transparent">
          Reports & Analytics
        </h2>
        <p className="text-gray-400 mt-1">Overview of your team's performance and metrics</p>
      </div>

      {/* Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
        <div className="bg-gradient-to-br from-blue-600 to-blue-800 p-6 rounded-2xl shadow-xl">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-blue-200 text-sm">Total Tasks</p>
              <p className="text-4xl font-bold text-white mt-2">{taskStats.total}</p>
            </div>
            <div className="w-14 h-14 bg-white/10 rounded-xl flex items-center justify-center">
              <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-6 9l2 2 4-4" />
              </svg>
            </div>
          </div>
          <div className="mt-4 flex items-center text-sm text-blue-200">
            <span className="text-green-400 font-semibold">{taskStats.completed}</span>
            <span className="mx-2">completed</span>
          </div>
        </div>

        <div className="bg-gradient-to-br from-green-600 to-green-800 p-6 rounded-2xl shadow-xl">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-green-200 text-sm">Completion Rate</p>
              <p className="text-4xl font-bold text-white mt-2">
                {taskStats.total > 0 ? Math.round((taskStats.completed / taskStats.total) * 100) : 0}%
              </p>
            </div>
            <div className="w-14 h-14 bg-white/10 rounded-xl flex items-center justify-center">
              <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" />
              </svg>
            </div>
          </div>
          <div className="mt-4 flex items-center text-sm text-green-200">
            <span className="text-white font-semibold">{taskStats.pending}</span>
            <span className="mx-2">pending tasks</span>
          </div>
        </div>

        <div className="bg-gradient-to-br from-purple-600 to-purple-800 p-6 rounded-2xl shadow-xl">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-purple-200 text-sm">Total Employees</p>
              <p className="text-4xl font-bold text-white mt-2">{employeeStats.total}</p>
            </div>
            <div className="w-14 h-14 bg-white/10 rounded-xl flex items-center justify-center">
              <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 20h5v-2a3 3 0 00-5.356-1.857M17 20H7m10 0v-2c0-.656-.126-1.283-.356-1.857M7 20H2v-2a3 3 0 015.356-1.857M7 20v-2c0-.656.126-1.283.356-1.857m0 0a5.002 5.002 0 019.288 0M15 7a3 3 0 11-6 0 3 3 0 016 0zm6 3a2 2 0 11-4 0 2 2 0 014 0zM7 10a2 2 0 11-4 0 2 2 0 014 0z" />
              </svg>
            </div>
          </div>
          <div className="mt-4 flex items-center text-sm text-purple-200">
            <span className="text-green-400 font-semibold">{employeeStats.active}</span>
            <span className="mx-2">active members</span>
          </div>
        </div>

        <div className="bg-gradient-to-br from-orange-600 to-red-800 p-6 rounded-2xl shadow-xl">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-orange-200 text-sm">Departments</p>
              <p className="text-4xl font-bold text-white mt-2">{employeeStats.departments.length}</p>
            </div>
            <div className="w-14 h-14 bg-white/10 rounded-xl flex items-center justify-center">
              <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-4h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" />
              </svg>
            </div>
          </div>
          <div className="mt-4 flex items-center text-sm text-orange-200">
            <span className="text-white font-semibold">{employeeStats.departments[0]?.name || 'N/A'}</span>
            <span className="mx-2">largest team</span>
          </div>
        </div>
      </div>

      {/* Charts Grid */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 mb-8">
        {/* Task Status Bar Chart */}
        <div className="bg-gray-800 p-6 rounded-2xl shadow-xl border border-gray-700">
          <h3 className="text-xl font-bold text-white mb-4">Tasks by Status</h3>
          <div className="h-72">
            <Bar data={taskStatusData} options={barChartOptions} />
          </div>
        </div>

        {/* Employee Status Pie Chart */}
        <div className="bg-gray-800 p-6 rounded-2xl shadow-xl border border-gray-700">
          <h3 className="text-xl font-bold text-white mb-4">Employee Status Distribution</h3>
          <div className="h-72 flex items-center justify-center">
            <Pie data={employeeStatusData} options={{ 
              responsive: true, 
              maintainAspectRatio: false,
              plugins: {
                legend: {
                  position: 'right',
                  labels: { color: '#9ca3af' }
                }
              }
            }} />
          </div>
        </div>

        {/* Department Distribution */}
        <div className="bg-gray-800 p-6 rounded-2xl shadow-xl border border-gray-700">
          <h3 className="text-xl font-bold text-white mb-4">Department Distribution</h3>
          <div className="h-72 flex items-center justify-center">
            <Doughnut data={departmentData} options={{ 
              responsive: true, 
              maintainAspectRatio: false,
              plugins: {
                legend: {
                  position: 'right',
                  labels: { color: '#9ca3af' }
                }
              }
            }} />
          </div>
        </div>

        {/* Task Priority */}
        <div className="bg-gray-800 p-6 rounded-2xl shadow-xl border border-gray-700">
          <h3 className="text-xl font-bold text-white mb-4">Task Priority Distribution</h3>
          <div className="h-72 flex items-center justify-center">
            <Doughnut data={priorityData} options={{ 
              responsive: true, 
              maintainAspectRatio: false,
              plugins: {
                legend: {
                  position: 'right',
                  labels: { color: '#9ca3af' }
                }
              }
            }} />
          </div>
        </div>
      </div>

      {/* Performance Trend */}
      <div className="bg-gray-800 p-6 rounded-2xl shadow-xl border border-gray-700">
        <h3 className="text-xl font-bold text-white mb-4">Performance Trend</h3>
        <div className="h-80">
          <Line data={trendData} options={{
            responsive: true,
            maintainAspectRatio: false,
            plugins: {
              legend: {
                position: 'top',
                labels: { color: '#9ca3af' }
              }
            },
            scales: {
              x: {
                ticks: { color: '#9ca3af' },
                grid: { color: '#374151' }
              },
              y: {
                ticks: { color: '#9ca3af' },
                grid: { color: '#374151' }
              }
            }
          }} />
        </div>
      </div>

      {/* Quick Stats Table */}
      <div className="mt-8 bg-gray-800 p-6 rounded-2xl shadow-xl border border-gray-700">
        <h3 className="text-xl font-bold text-white mb-4">Quick Statistics</h3>
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
          <div className="bg-gray-700/50 p-4 rounded-xl">
            <p className="text-gray-400 text-sm">High Priority Tasks</p>
            <p className="text-2xl font-bold text-red-400 mt-1">
              {tasks.filter(t => t.priority === 'high').length}
            </p>
          </div>
          <div className="bg-gray-700/50 p-4 rounded-xl">
            <p className="text-gray-400 text-sm">In Progress Tasks</p>
            <p className="text-2xl font-bold text-blue-400 mt-1">{taskStats.inProgress}</p>
          </div>
          <div className="bg-gray-700/50 p-4 rounded-xl">
            <p className="text-gray-400 text-sm">On Leave</p>
            <p className="text-2xl font-bold text-yellow-400 mt-1">{employeeStats.onLeave}</p>
          </div>
          <div className="bg-gray-700/50 p-4 rounded-xl">
            <p className="text-gray-400 text-sm">Inactive</p>
            <p className="text-2xl font-bold text-gray-400 mt-1">{employeeStats.inactive}</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Reports;
